int main() {
    // Optimize C++ standard streams for competitive programming.
    // This unties cin from cout and disables synchronization with C's stdio.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int Y, W; // Declare variables for Yakko's and Wakko's die rolls
    std::cin >> Y >> W; // Read Yakko's and Wakko's scores from standard input

    // Dot wins if her roll is greater than or equal to both Yakko's and Wakko's rolls.
    // This means Dot's roll must be greater than or equal to the maximum of Y and W.
    int max_opponent_roll = std::max(Y, W);

    // Dot rolls a standard six-sided die. The possible outcomes are 1, 2, 3, 4, 5, 6.
    // We need to count how many of these outcomes satisfy Dot's winning condition.
    // If max_opponent_roll is K, Dot wins if she rolls K, K+1, ..., 6.
    // The number of such favorable outcomes is (6 - K + 1).
    // For example, if K=4, favorable outcomes are 4, 5, 6 (3 outcomes).
    // Calculation: 6 - 4 + 1 = 3.
    int favorable_outcomes = 6 - max_opponent_roll + 1;

    // The total number of possible outcomes for Dot's die roll is always 6.
    int total_outcomes = 6;

    // To output the probability as an irreducible fraction, we need to divide
    // both the numerator (favorable_outcomes) and the denominator (total_outcomes)
    // by their greatest common divisor (GCD).
    int common_divisor = std::gcd(favorable_outcomes, total_outcomes);

    // Output the simplified fraction in the format "A/B".
    std::cout << favorable_outcomes / common_divisor << "/" << total_outcomes / common_divisor << std::endl;

    return 0; // Indicate successful execution
}

