#include <iostream>
#include <vector>
#include <string>
#include <map>
#include <algorithm>
#include <functional> // For std::greater

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<int> prices(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> prices[i];
    }

    // Count the occurrences of each fruit Valera wants
    std::map<std::string, int> fruit_counts;
    for (int i = 0; i < m; ++i) {
        std::string fruit_name;
        std::cin >> fruit_name;
        fruit_counts[fruit_name]++;
    }

    // Extract the counts of distinct fruits Valera wants into a vector
    // and sort them in descending order. This ensures that fruits Valera
    // wants more often are considered first.
    std::vector<int> counts;
    for (auto const& pair : fruit_counts) {
        counts.push_back(pair.second);
    }
    std::sort(counts.begin(), counts.end(), std::greater<int>());

    // Calculate Minimum Price
    // To minimize the total price, we assign the cheapest available prices
    // to the fruits Valera wants most frequently.
    std::sort(prices.begin(), prices.end()); // Sort prices in ascending order
    long long min_total_price = 0;
    for (int i = 0; i < counts.size(); ++i) {
        // counts[i] is the frequency of the i-th most wanted fruit
        // prices[i] is the i-th cheapest price
        min_total_price += (long long)counts[i] * prices[i];
    }

    // Calculate Maximum Price
    // To maximize the total price, we assign the most expensive available prices
    // to the fruits Valera wants most frequently.
    std::sort(prices.begin(), prices.end(), std::greater<int>()); // Sort prices in descending order
    long long max_total_price = 0;
    for (int i = 0; i < counts.size(); ++i) {
        // counts[i] is the frequency of the i-th most wanted fruit
        // prices[i] is the i-th most expensive price
        max_total_price += (long long)counts[i] * prices[i];
    }

    std::cout << min_total_price << " " << max_total_price << std::endl;

    return 0;
}

